#!/usr/bin/env node
/**
 * Generate Sitemap Index for Z-Beam
 * 
 * Creates a sitemap index that references:
 * - Main sitemap (sitemap.xml - generated by Next.js)
 * - Image sitemap (image-sitemap.xml)
 * 
 * Google sitemap index requirements:
 * - List all sitemaps
 * - Include lastmod dates
 * - Keep under 50MB and 50,000 sitemap entries
 * 
 * Usage: node scripts/seo/generate-sitemap-index.js
 */

const fs = require('fs').promises;
const path = require('path');

// Configuration
// BASE_URL imported from config/urls.js
// Provides environment-aware URL resolution
const PUBLIC_DIR = path.join(__dirname, '../../public');
const OUTPUT_FILE = path.join(PUBLIC_DIR, 'sitemap-index.xml');

/**
 * Build sitemap index XML
 */
function buildSitemapIndex() {
  const now = new Date().toISOString();
  
  return `<?xml version="1.0" encoding="UTF-8"?>
<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <sitemap>
    <loc>${BASE_URL}/sitemap.xml</loc>
    <lastmod>${now}</lastmod>
  </sitemap>
  <sitemap>
    <loc>${BASE_URL}/image-sitemap.xml</loc>
    <lastmod>${now}</lastmod>
  </sitemap>
</sitemapindex>`;
}

/**
 * Main execution
 */
async function main() {
  console.log('🗺️  Z-Beam Sitemap Index Generator');
  console.log('═══════════════════════════════════════\n');
  
  try {
    // Build sitemap index
    console.log('🔨 Building sitemap index...');
    const sitemapIndex = buildSitemapIndex();
    
    // Write to file
    await fs.writeFile(OUTPUT_FILE, sitemapIndex, 'utf-8');
    console.log(`✅ Sitemap index created: ${OUTPUT_FILE}\n`);
    
    console.log('📋 Included sitemaps:');
    console.log('   1. sitemap.xml (main content sitemap)');
    console.log('   2. image-sitemap.xml (684 images)\n');
    
    console.log('✨ Next steps:');
    console.log('   1. Update robots.txt to reference sitemap-index.xml');
    console.log('   2. Deploy to production');
    console.log('   3. Submit sitemap-index.xml to Google Search Console');
    console.log('   4. Monitor crawl stats and indexing\n');
    
  } catch (error) {
    console.error('❌ Error generating sitemap index:', error);
    process.exit(1);
  }
}

// Run if executed directly
if (require.main === module) {
  main();
}

module.exports = { buildSitemapIndex };
